// One LegiScan full-text query per item. Tuned to the BDD beat: data centers,
// water/groundwater, eminent domain/transmission, large electric loads.
const queries = [
  'data center',
  'data center water',
  'groundwater conservation district',
  'eminent domain transmission line',
  'large load electric'
];
return queries.map(q => ({ json: { query: q } }));

// Collect unique bills across all getSearch responses. The searchresult object
// has a 'summary' key plus numbered keys (0,1,2,...) each holding one bill hit.
const items = $input.all();
const seen = {};
const out = [];
for (const it of items) {
  const sr = it.json && it.json.searchresult;
  if (!sr) continue;
  for (const k of Object.keys(sr)) {
    if (k === 'summary') continue;
    const r = sr[k];
    if (!r || !r.bill_id) continue;
    if (seen[r.bill_id]) continue;
    seen[r.bill_id] = true;
    out.push({ json: {
      bill_id: r.bill_id,
      bill_number: r.bill_number,
      title: r.title,
      change_hash: r.change_hash,
      last_action: r.last_action,
      last_action_date: r.last_action_date,
      url: r.url,
      relevance: r.relevance
    }});
  }
}
return out;

