// Combine getBill detail + Gemini summary + the search hit into one validated
// legislation JSON file, mapping LegiScan's numeric status to our vocabulary.
let g = {};
try {
  const t = ($json.candidates?.[0]?.content?.parts?.[0]?.text || '{}').trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
  g = JSON.parse(t);
} catch (e) { g = {}; }

const bill = ($('LegiScan: getBill').item.json && $('LegiScan: getBill').item.json.bill) || {};
const search = $('Collect bills').item.json || {};

// LegiScan progress: 1 Introduced, 2 Engrossed, 3 Enrolled, 4 Passed, 5 Vetoed, 6 Failed.
const MAP = { 1: { c: 'bill', s: 'filed' }, 2: { c: 'bill', s: 'passed' }, 3: { c: 'bill', s: 'passed' }, 4: { c: 'statute', s: 'in-effect' }, 5: { c: 'bill', s: 'failed' }, 6: { c: 'bill', s: 'failed' } };
const m = MAP[bill.status] || { c: 'bill', s: 'filed' };

const rawNum = (bill.bill_number || search.bill_number || '').toString();
const billNumber = rawNum.replace(/^([A-Za-z]+)0*(\d+)$/, '$1 $2');
const sessionName = (bill.session && (bill.session.session_name || bill.session.session_title)) || '';
const sessionTag = (sessionName.match(/\d+\w?/) || [''])[0];
const harm = Array.isArray(g.harm) ? g.harm.filter(h => ['water', 'air', 'property'].includes(h)) : [];
const summary = (g.summary || '').toString().trim();
if (!summary) return [];

const slug = ('tx-' + (sessionTag || 'session') + '-' + rawNum).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

const existing = $('Get existing legislation').all()
  .flatMap(it => Array.isArray(it.json) ? it.json : [it.json])
  .map(f => (f && f.name ? String(f.name).replace(/\.json$/, '') : ''))
  .filter(Boolean);
const isNew = !existing.includes(slug);

const obj = {
  category: m.c,
  title: (billNumber + ' — ' + (bill.title || search.title || '')).slice(0, 90),
  billNumber: billNumber,
  session: sessionName || undefined,
  jurisdiction: 'Texas',
  status: m.s,
  chamber: /^s/i.test(rawNum) ? 'senate' : 'house',
  harm: harm,
  summary: summary,
  whyItMatters: (g.whyItMatters || '').toString().trim() || undefined,
  sourceUrl: bill.state_link || search.url || bill.url,
  sourceName: 'Texas Legislature Online',
  lastAction: search.last_action || undefined,
  lastActionDate: search.last_action_date || undefined,
  legiscanId: bill.bill_id || search.bill_id,
  dateFound: new Date().toISOString().slice(0, 10)
};
const contentB64 = Buffer.from(JSON.stringify(obj, null, 2) + '\n', 'utf8').toString('base64');
return [{ json: { slug, path: 'src/content/legislation/' + slug + '.json', title: obj.title, contentB64, isNew, billNumber } }];
